define([],function(){return{init:function(){if(!document.body.classList.contains("format-archive")){return}var setup=function(){var btn=document.getElementById("collapsesections");if(!btn){setTimeout(setup,300);return}btn.addEventListener("click",function(e){e.preventDefault();e.stopImmediatePropagation();var collapseSpan=btn.querySelector(".collapseall");var shouldCollapse=collapseSpan&&window.getComputedStyle(collapseSpan).display!=="none";var sections=document.querySelectorAll('[id^="coursecontentcollapseid"]');sections.forEach(function(section){if(shouldCollapse){section.classList.remove("show")}else{section.classList.add("show")}});var togglers=document.querySelectorAll('[id^="collapsesectionid"]');togglers.forEach(function(toggler){if(shouldCollapse){toggler.classList.add("collapsed");toggler.setAttribute("aria-expanded","false")}else{toggler.classList.remove("collapsed");toggler.setAttribute("aria-expanded","true")}});if(shouldCollapse){btn.classList.add("collapsed");btn.setAttribute("aria-expanded","false")}else{btn.classList.remove("collapsed");btn.setAttribute("aria-expanded","true")}})};setup()}}});